// Nudge day 2, day 5, day 10 after submission. After 3 nudges → dormant.
const now = Date.now();
const DAY = 24 * 60 * 60 * 1000;
const schedule = [2, 5, 10]; // days after submission
const out = [];
for (const item of $input.all()) {
  const r = item.json;
  if (r.status !== 'new' || !r.email) continue;
  const nudges = Number(r.nudge_count || 0);
  if (nudges >= 3) continue;
  const submitted = new Date(r.submitted_at).getTime();
  if (!submitted) continue;
  const dueAt = submitted + schedule[nudges] * DAY;
  if (now >= dueAt) {
    out.push({ json: { ...r, nudge_count: nudges, next_nudge: nudges + 1, goes_dormant: nudges + 1 >= 3 } });
  }
}
return out;
